    70→size_t HeaderMapImpl::HeaderList::remove(absl::string_view key) {
    71→  size_t removed_bytes = 0;
    72→  if (maybeMakeMap()) {
    73→    auto iter = lazy_map_.find(key);
    74→    if (iter != lazy_map_.end()) {
    75→      // Erase from the map, and all same key entries from the list.
    76→      HeaderNodeVector header_nodes = std::move(iter->second);
    77→      lazy_map_.erase(iter);
    78→      for (const HeaderNode& node : header_nodes) {
    79→        ASSERT(node->key() == key);
    80→        removed_bytes += node->key().size() + node->value().size();
    81→        erase(node, false /* remove_from_map */);
    82→      }
    83→    }
    84→  } else {
    85→    // Erase all same key entries from the list.
    86→    for (auto i = headers_.begin(); i != headers_.end();) {
    87→      if (i->key() == key) {
    88→        removed_bytes += i->key().size() + i->value().size();
    89→        i = erase(i, false /* remove_from_map */);
    90→      } else {
    91→        ++i;
    92→      }
    93→    }
    94→  }
    95→  return removed_bytes;
